class Solution:
    def maxScore(self, nums, maxVal):
        n = len(nums)
        valset = set(nums)
        candidates = set(range(1, maxVal + 1))
        for x in nums:
            if x > maxVal:
                candidates.add(x)
        best = -10**18
        for v in candidates:
            conflict = sum(1 for x in nums if gcd(x, v) != 1)
            has_v = v in valset
            if v > maxVal or has_v:
                cost = conflict - 1
            elif conflict >= 1:
                cost = conflict
            else:
                cost = 1
            score = v - cost
            if score > best:
                best = score
        return best

