class Solution:
    def maxScore(self, nums, maxVal: int) -> int:
        n = len(nums)
        V = max([maxVal] + nums)
        freq = [0] * (V + 2)
        for x in nums:
            freq[x] += 1
        divCount = [0] * (V + 1)
        for d in range(1, V + 1):
            s = 0
            m = d
            while m <= V:
                s += freq[m]
                m += d
            divCount[d] = s
        spf = list(range(V + 1))
        i = 2
        while i * i <= V:
            if spf[i] == i:
                for j in range(i * i, V + 1, i):
                    if spf[j] == j:
                        spf[j] = i
            i += 1

        def prime_factors(x):
            ps = []
            while x > 1:
                p = spf[x]
                ps.append(p)
                while x % p == 0:
                    x //= p
            return ps

        def conflict_of(v):
            if v == 1:
                return 0
            pf = prime_factors(v)
            k = len(pf)
            coprimeCount = 0
            for mask in range(1 << k):
                prod = 1
                bits = 0
                b = 0
                mm = mask
                while mm:
                    if mm & 1:
                        prod *= pf[b]
                        bits += 1
                    mm >>= 1
                    b += 1
                sign = -1 if bits % 2 else 1
                coprimeCount += sign * divCount[prod]
            return n - coprimeCount

        valset = set(nums)
        candidates = set(range(1, maxVal + 1))
        for x in nums:
            if x > maxVal:
                candidates.add(x)
        best = -10**18
        for v in candidates:
            conflict = conflict_of(v)
            has_v = v in valset
            if v > maxVal or has_v:
                cost = conflict - 1
            elif conflict >= 1:
                cost = conflict
            else:
                cost = 1
            score = v - cost
            if score > best:
                best = score
        return best

