var maxScore = function(nums, maxVal) {
    const n = nums.length;
    const V = Math.max(maxVal, ...nums);
    const freq = new Array(V + 2).fill(0);
    for (const x of nums) freq[x]++;
    const divCount = new Array(V + 1).fill(0);
    for (let d = 1; d <= V; d++) {
        let s = 0;
        for (let m = d; m <= V; m += d) s += freq[m];
        divCount[d] = s;
    }
    const spf = new Array(V + 1);
    for (let i = 0; i <= V; i++) spf[i] = i;
    for (let i = 2; i * i <= V; i++) {
        if (spf[i] === i) {
            for (let j = i * i; j <= V; j += i) {
                if (spf[j] === j) spf[j] = i;
            }
        }
    }
    function primeFactors(x) {
        const ps = [];
        while (x > 1) {
            const p = spf[x];
            ps.push(p);
            while (x % p === 0) x = Math.floor(x / p);
        }
        return ps;
    }
    function conflictOf(v) {
        if (v === 1) return 0;
        const pf = primeFactors(v);
        const k = pf.length;
        let coprimeCount = 0;
        for (let mask = 0; mask < (1 << k); mask++) {
            let prod = 1;
            let bits = 0;
            for (let b = 0; b < k; b++) {
                if (mask & (1 << b)) {
                    prod *= pf[b];
                    bits++;
                }
            }
            const sign = (bits % 2) ? -1 : 1;
            coprimeCount += sign * divCount[prod];
        }
        return n - coprimeCount;
    }
    const valset = new Set(nums);
    const candidates = new Set();
    for (let v = 1; v <= maxVal; v++) candidates.add(v);
    for (const x of nums) {
        if (x > maxVal) candidates.add(x);
    }
    let best = -Infinity;
    for (const v of candidates) {
        const conflict = conflictOf(v);
        const hasV = valset.has(v);
        let cost;
        if (v > maxVal || hasV) cost = conflict - 1;
        else if (conflict >= 1) cost = conflict;
        else cost = 1;
        const score = v - cost;
        if (score > best) best = score;
    }
    return best;
};
